const status = items[0].json;
const now = new Date();

// 檢查用量
const inputTokens = status.tokens?.input || 0;
const outputTokens = status.tokens?.output || 0;
const cost = status.cost || 0;

// 計算每小時用量
const hourlyCost = cost / 24;

let alerts = [];

if (hourlyCost > 0.1) {
  alerts.push({
    level: 'warning',
    message: `每小時費用偏高: $${hourlyCost.toFixed(4)}`,
    threshold: 0.1
  });
}

if (inputTokens > 10000) {
  alerts.push({
    level: 'info',
    message: `輸入tokens使用量: ${inputTokens}`,
    threshold: 10000
  });
}

return [{
  json: {
    timestamp: now.toISOString(),
    status: 'healthy',
    metrics: {
      inputTokens,
      outputTokens,
      cost,
      hourlyCost
    },
    alerts
  }
}];

